using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using System.Text.Json.Serialization;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;

namespace ResearchAgent;

/// <summary>
/// Provides web search capabilities to the research agent.
/// Uses the Brave Search API when a key is configured; falls back to a
/// simulated provider so the app can be demonstrated without any API key.
/// </summary>
public sealed class WebSearchTool(HttpClient httpClient, ILogger<WebSearchTool> logger)
{
    [Description("Search the web for information on a given query. Returns a list of relevant results with titles, URLs, and descriptions.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5,
        CancellationToken cancellationToken = default)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);
        logger.LogInformation("Searching the web for: {Query} (max {Max} results)", query, maxResults);

        var braveApiKey = Environment.GetEnvironmentVariable("BRAVE_API_KEY");
        if (!string.IsNullOrWhiteSpace(braveApiKey))
        {
            return await SearchBraveAsync(query, maxResults, braveApiKey, cancellationToken);
        }

        logger.LogWarning("BRAVE_API_KEY not set — using simulated search results");
        return GetSimulatedResults(query);
    }

    private async Task<string> SearchBraveAsync(
        string query, int maxResults, string apiKey, CancellationToken cancellationToken)
    {
        var request = new HttpRequestMessage(HttpMethod.Get,
            $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count={maxResults}");
        request.Headers.Add("Accept", "application/json");
        request.Headers.Add("X-Subscription-Token", apiKey);

        var response = await httpClient.SendAsync(request, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        var results = new List<object>();

        if (json.TryGetProperty("web", out var web) && web.TryGetProperty("results", out var items))
        {
            foreach (var item in items.EnumerateArray().Take(maxResults))
            {
                results.Add(new
                {
                    title = item.GetProperty("title").GetString(),
                    url = item.GetProperty("url").GetString(),
                    description = item.TryGetProperty("description", out var desc)
                        ? desc.GetString() : ""
                });
            }
        }

        return JsonSerializer.Serialize(results, SearchJsonContext.Default.ListObject);
    }

    private static string GetSimulatedResults(string query)
    {
        var results = new List<object>
        {
            new
            {
                title = $"Overview of {query} - Wikipedia",
                url = $"https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}",
                description = $"A comprehensive encyclopedia article providing background, history, and key concepts related to {query}."
            },
            new
            {
                title = $"Latest developments in {query} - TechReview",
                url = $"https://techreview.example.com/{Uri.EscapeDataString(query)}",
                description = $"Recent advances and breakthroughs in {query}, including expert opinions and industry analysis."
            },
            new
            {
                title = $"{query}: A Practical Guide - DevBlog",
                url = $"https://devblog.example.com/guide/{Uri.EscapeDataString(query)}",
                description = $"A hands-on guide covering practical applications, best practices, and common pitfalls of {query}."
            },
            new
            {
                title = $"Research Papers on {query} - ArXiv",
                url = $"https://arxiv.example.com/search?q={Uri.EscapeDataString(query)}",
                description = $"Collection of peer-reviewed research papers exploring theoretical foundations and experimental results in {query}."
            },
            new
            {
                title = $"Community Discussion: {query} - Forum",
                url = $"https://forum.example.com/topics/{Uri.EscapeDataString(query)}",
                description = $"Community-driven discussion threads about real-world experiences, tips, and resources for {query}."
            }
        };

        return JsonSerializer.Serialize(results, SearchJsonContext.Default.ListObject);
    }
}

[JsonSerializable(typeof(List<object>))]
internal partial class SearchJsonContext : JsonSerializerContext;

using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.Logging;

namespace ResearchAgent;

/// <summary>
/// Provides note-taking capabilities so the agent can persist and
/// organize research findings across multiple tool-calling iterations.
/// </summary>
public sealed class NoteTakingTool(ILogger<NoteTakingTool> logger)
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a title and content. Use this to record key findings from web searches.")]
    public string SaveNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("The content/body of the note")] string content,
        [Description("Source URL where the information was found, if any")] string? sourceUrl = null)
    {
        var note = new Note(title, content, sourceUrl);
        _notes.Add(note);
        logger.LogInformation("Note saved: {Title} ({Count} total)", title, _notes.Count);
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            var n = _notes[i];
            sb.AppendLine($"--- Note #{i + 1}: {n.Title} ---");
            sb.AppendLine(n.Content);
            if (!string.IsNullOrEmpty(n.SourceUrl))
                sb.AppendLine($"Source: {n.SourceUrl}");
            sb.AppendLine();
        }

        return sb.ToString();
    }

    [Description("Search through saved notes for a specific keyword or phrase.")]
    public string SearchNotes(
        [Description("The keyword or phrase to search for in note titles and content")] string keyword)
    {
        var matches = _notes
            .Where(n => n.Title.Contains(keyword, StringComparison.OrdinalIgnoreCase)
                     || n.Content.Contains(keyword, StringComparison.OrdinalIgnoreCase))
            .ToList();

        if (matches.Count == 0)
            return $"No notes found matching \"{keyword}\".";

        var sb = new StringBuilder();
        sb.AppendLine($"Found {matches.Count} note(s) matching \"{keyword}\":");
        foreach (var n in matches)
        {
            sb.AppendLine($"- {n.Title}: {n.Content[..Math.Min(n.Content.Length, 150)]}...");
        }

        return sb.ToString();
    }

    private sealed record Note(string Title, string Content, string? SourceUrl);
}

