using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

// --- AI provider ----------------------------------------------------------
// Reads OPENAI_API_KEY / OPENAI_MODEL from the environment.
// Default model: gpt-4o-mini-2024-07-18 (cost-effective for research tasks).
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b.UseOpenAIChatClient(modelId, new(apiKey)));

builder.Services.AddHttpClient<WebSearchTool>();
builder.Services.AddSingleton<NoteTakingTool>();

builder.Services.AddLogging(cfg => cfg
    .SetMinimumLevel(LogLevel.Information)
    .AddSimpleConsole(o =>
    {
        o.SingleLine = true;
        o.TimestampFormat = "HH:mm:ss ";
    }));

var host = builder.Build();

// --- Resolve services -----------------------------------------------------
var chatClient = host.Services.GetRequiredService<IChatClient>();
var searchTool = host.Services.GetRequiredService<WebSearchTool>();
var noteTool   = host.Services.GetRequiredService<NoteTakingTool>();
var loggerFactory = host.Services.GetRequiredService<ILoggerFactory>();

// --- Build tool list from annotated methods -------------------------------
var tools = new List<AITool>
{
    AIFunctionFactory.Create(searchTool.SearchWebAsync),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetAllNotes),
    AIFunctionFactory.Create(noteTool.SearchNotes),
};

// --- Create the research agent --------------------------------------------
const string instructions = """
    You are a research agent. Your goal is to thoroughly research a topic 
    provided by the user and produce a well-organized summary.

    Follow this workflow:
    1. Break the topic into 2-3 specific sub-questions.
    2. For each sub-question, use the SearchWeb tool to find relevant information.
    3. Use the SaveNote tool to record key findings from each search, including
       the source URL.
    4. After gathering enough information, use GetAllNotes to review your findings.
    5. Produce a final summary that synthesizes all your notes into a coherent,
       well-structured report with sections and source citations.

    Be thorough but concise. Cite sources by URL where possible.
    """;

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes",
    instructions: instructions,
    tools: tools,
    loggerFactory: loggerFactory);

// --- Interactive loop -----------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔍 Research Agent (MAF)          ║");
Console.WriteLine("║  Type a topic to research, or 'quit'.   ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine("Researching... (the agent will search and take notes autonomously)");
    Console.ResetColor();
    Console.WriteLine();

    try
    {
        var session = await agent.CreateSessionAsync(conversationId: null);

        var runOptions = new ChatClientAgentRunOptions(new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
        });

        var response = await agent.RunAsync(
            $"Please research the following topic and produce a comprehensive summary: {topic}",
            session,
            runOptions);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("═══ Research Summary ═══");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
        Console.WriteLine();
    }
}

